import os
from github import Github

GITHUB_TOKEN = os.getenv("GITHUB_TOKEN")
GITHUB_USER = os.getenv("GITHUB_USER")

g = Github(GITHUB_TOKEN)


def create_or_update_repo(project_type):

    repo_name = "atlas-" + project_type.replace(" ", "-").lower()

    user = g.get_user()

    try:
        repo = user.get_repo(repo_name)
        version = "v2"
    except:
        repo = user.create_repo(repo_name)
        version = "v1"

    files = {

        "README.md": f"# {repo_name}\n\nGenerated by Atlas AI\n",

        "package.json": """
{
  "name": "atlas-app",
  "private": true,
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start"
  },
  "dependencies": {
    "next": "latest",
    "react": "latest",
    "react-dom": "latest",
    "@supabase/supabase-js": "latest",
    "stripe": "latest"
  }
}
""",

        "pages/index.js": """
export default function Home() {
  return (
    <div style={{padding:40}}>
      <h1>Atlas Generated App</h1>
      <p>Your AI generated project is ready.</p>
    </div>
  )
}
""",

        "lib/supabase.js": """
import { createClient } from '@supabase/supabase-js'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_KEY

export const supabase = createClient(supabaseUrl, supabaseKey)
""",

        "pages/api/orders.js": """
export default async function handler(req, res) {

  if (req.method === 'POST') {

    const order = req.body

    console.log("New order:", order)

    res.status(200).json({ success: true })

  } else {

    res.status(405).json({ error: 'Method not allowed' })

  }
}
""",

        "pages/api/checkout.js": """
import Stripe from 'stripe'

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY)

export default async function handler(req, res) {

  const session = await stripe.checkout.sessions.create({
    payment_method_types: ['card'],
    line_items: [
      {
        price_data: {
          currency: 'usd',
          product_data: { name: 'Atlas Product' },
          unit_amount: 500
        },
        quantity: 1
      }
    ],
    mode: 'payment',
    success_url: 'http://localhost:3000',
    cancel_url: 'http://localhost:3000'
  })

  res.json({ url: session.url })
}
"""
    }

    for path, content in files.items():

        try:
            existing = repo.get_contents(path)

            repo.update_file(
                existing.path,
                "Atlas automated update",
                content,
                existing.sha
            )

        except:
            repo.create_file(
                path,
                "Atlas automated project build",
                content
            )

    return repo_name, version
